        return Err(anyhow!("Model '{model}' not found. Pull it: `ollama pull {model}`"));
    }
    if status.as_u16() == 404 {
        return Err(anyhow!("Endpoint not found (404 at {url}). Check --ollama-url"));
    }
    Err(anyhow!("Ollama failed: {status} — {err_msg}"))
}

